+// generatePolecatName generates a unique polecat name that doesn't conflict with existing ones.
+func generatePolecatName(mgr *polecat.Manager) string {
+	existing, _ := mgr.List()
+	existingNames := make(map[string]bool)
+	for _, p := range existing {
